 1→import { and, desc, eq, ilike, isNull, or, sql } from "drizzle-orm";
 2→import { type NextRequest, NextResponse } from "next/server";
 3→import { db } from "@/src/db";
 4→import { jobs } from "@/src/db/schema";
 5→import { escapeLike } from "@/src/lib/helpers";
 6→import { parsePagination } from "@/src/lib/pagination";
 7→
 8→export const dynamic = "force-dynamic";
 9→
10→export async function GET(req: NextRequest) {
11→  const params = req.nextUrl.searchParams;
12→  const q = params.get("q")?.trim() ?? "";
13→  const platform = params.get("platform") ?? "";
14→  const provincie = params.get("provincie") ?? "";
15→  const { page, limit, offset } = parsePagination(params, { limit: 10 });
16→
17→  const conditions = [isNull(jobs.deletedAt)];
18→
19→  // Multi-field search with ILIKE across title, company, description, location
20→  if (q.length >= 2) {
21→    const pattern = `%${escapeLike(q)}%`;
22→    const searchCondition = or(
23→      ilike(jobs.title, pattern),
24→      ilike(jobs.company, pattern),
25→      ilike(jobs.description, pattern),
26→      ilike(jobs.location, pattern),
27→      ilike(jobs.platform, pattern),
28→    );
29→    if (searchCondition) conditions.push(searchCondition);
30→  }
31→
32→  if (platform) {
33→    conditions.push(eq(jobs.platform, platform));
34→  }
35→
36→  if (provincie) {
37→    conditions.push(ilike(jobs.location, `%${escapeLike(provincie)}%`));
38→  }
39→
40→  const whereClause = and(...conditions);
41→
42→  const [rows, countResult] = await Promise.all([
43→    db
44→      .select({
45→        id: jobs.id,
46→        title: jobs.title,
47→        company: jobs.company,
48→        location: jobs.location,
49→        platform: jobs.platform,
50→        workArrangement: jobs.workArrangement,
51→        contractType: jobs.contractType,
52→      })
53→      .from(jobs)
54→      .where(whereClause)
55→      .orderBy(desc(jobs.scrapedAt))
56→      .limit(limit)
57→      .offset(offset),
58→    db.select({ count: sql<number>`count(*)::int` }).from(jobs).where(whereClause),
59→  ]);
60→
61→  const total = countResult[0]?.count ?? 0;
62→
63→  return NextResponse.json({
64→    jobs: rows,
65→    total,
66→    page,
67→    perPage: limit,
68→    totalPages: Math.ceil(total / limit),
69→  });
70→}
