 1→import * as Sentry from "@sentry/nextjs";
 2→import { rateLimit } from "./rate-limit";
 3→
 4→type ApiHandler<TArgs extends unknown[]> = (...args: TArgs) => Response | Promise<Response>;
 5→
 6→type ApiHandlerOptions = {
 7→  errorMessage?: string;
 8→  status?: number;
 9→  logPrefix?: string;
10→  /** Rate limit config — omit to skip rate limiting */
11→  rateLimit?: { interval: number; limit: number };
12→};
13→
14→// Pre-built rate limiters per tier to avoid creating new instances per request
15→const limiters = new Map<string, ReturnType<typeof rateLimit>>();
16→
17→function getLimiter(key: string, interval: number, limit: number) {
18→  if (!limiters.has(key)) {
19→    limiters.set(key, rateLimit({ interval, limit }));
20→  }
21→  return limiters.get(key) ?? rateLimit({ interval, limit });
22→}
23→
24→/** Extract client IP from request headers (works with Vercel, Cloudflare, etc.) */
25→function extractIp(request: Request): string {
26→  return (
27→    request.headers.get("x-real-ip") ??
28→    request.headers.get("x-forwarded-for")?.split(",")[0].trim() ??
29→    "anonymous"
30→  );
31→}
32→
33→export function withApiHandler<TArgs extends unknown[]>(
34→  handler: ApiHandler<TArgs>,
35→  options: ApiHandlerOptions = {},
36→) {
37→  const {
38→    errorMessage = "Interne serverfout",
39→    status = 500,
40→    logPrefix = "API handler error",
41→  } = options;
42→
43→  const limiterKey = logPrefix; // Use log prefix as limiter identity
44→
45→  return async (...args: TArgs): Promise<Response> => {
46→    // Rate limiting check (if configured)
47→    if (options.rateLimit) {
48→      const limiter = getLimiter(limiterKey, options.rateLimit.interval, options.rateLimit.limit);
49→      const request = args[0] as Request;
50→      const ip = extractIp(request);
51→      const { success, reset } = limiter.check(ip);
52→      if (!success) {
53→        return Response.json(
54→          { error: "Te veel verzoeken. Probeer het later opnieuw." },
55→          {
56→            status: 429,
57→            headers: { "Retry-After": String(Math.ceil((reset - Date.now()) / 1000)) },
58→          },
59→        );
60→      }
61→    }
62→
63→    try {
64→      return await handler(...args);
65→    } catch (error) {
66→      console.error(`${logPrefix}:`, error);
67→      Sentry.captureException(error, { tags: { source: "api-handler" } });
68→      return Response.json({ error: errorMessage }, { status });
69→    }
70→  };
71→}
