  1→import { and, desc, eq, ilike, isNull, sql } from "drizzle-orm";
  2→import { Euro, MapPin, Search, UserPlus, Users, Zap } from "lucide-react";
  3→import Link from "next/link";
  4→import { AddCandidateDialog } from "@/components/add-candidate-dialog";
  5→import { DraggableCandidate } from "@/components/draggable-candidate";
  6→import { EmptyState } from "@/components/shared/empty-state";
  7→import { KPICard } from "@/components/shared/kpi-card";
  8→import { Pagination } from "@/components/shared/pagination";
  9→import { Badge } from "@/components/ui/badge";
 10→import { db } from "@/src/db";
 11→import { candidates } from "@/src/db/schema";
 12→import { escapeLike } from "@/src/lib/helpers";
 13→
 14→export const dynamic = "force-dynamic";
 15→
 16→interface Props {
 17→  searchParams: Promise<{
 18→    q?: string;
 19→    beschikbaarheid?: string;
 20→    pagina?: string;
 21→  }>;
 22→}
 23→
 24→const PER_PAGE = 20;
 25→
 26→const availabilityLabels: Record<string, string> = {
 27→  direct: "Direct beschikbaar",
 28→  "1_maand": "Binnen 1 maand",
 29→  "3_maanden": "Binnen 3 maanden",
 30→};
 31→
 32→export default async function ProfessionalsPage({ searchParams }: Props) {
 33→  const params = await searchParams;
 34→  const query = params.q ?? "";
 35→  const availability = params.beschikbaarheid ?? "";
 36→  const page = Math.max(1, parseInt(params.pagina ?? "1", 10));
 37→  const offset = (page - 1) * PER_PAGE;
 38→
 39→  // Build conditions
 40→  const conditions = [isNull(candidates.deletedAt)];
 41→
 42→  if (query) {
 43→    conditions.push(ilike(candidates.name, `%${escapeLike(query)}%`));
 44→  }
 45→  if (availability) {
 46→    conditions.push(eq(candidates.availability, availability));
 47→  }
 48→
 49→  const whereClause = and(...conditions);
 50→
 51→  // Fetch candidates + consolidated counts in parallel (reduces DB connections)
 52→  const oneWeekAgo = new Date();
 53→  oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);
 54→
 55→  // Extra filter conditions beyond isNull(deletedAt) for the filtered count
 56→  const extraFilters = conditions.length > 1 ? and(...conditions.slice(1)) : null;
 57→
 58→  const [candidateRows, statsResult] = await Promise.all([
 59→    db
 60→      .select()
 61→      .from(candidates)
 62→      .where(whereClause)
 63→      .orderBy(desc(candidates.createdAt))
 64→      .limit(PER_PAGE)
 65→      .offset(offset),
 66→    // All 3 counts in a single query using FILTER clauses
 67→    db
 68→      .select({
 69→        totalFiltered: extraFilters
 70→          ? sql<number>`count(*) filter (where ${extraFilters})::int`
 71→          : sql<number>`count(*)::int`,
 72→        directCount: sql<number>`count(*) filter (where ${candidates.availability} = 'direct')::int`,
 73→        weekCount: sql<number>`count(*) filter (where ${candidates.createdAt} >= ${oneWeekAgo})::int`,
 74→      })
 75→      .from(candidates)
 76→      .where(isNull(candidates.deletedAt)),
 77→  ]);
 78→
 79→  const totalCount = statsResult[0]?.totalFiltered ?? 0;
 80→  const totalPages = Math.ceil(totalCount / PER_PAGE);
 81→  const directCount = statsResult[0]?.directCount ?? 0;
 82→  const weekCount = statsResult[0]?.weekCount ?? 0;
 83→
 84→  return (
 85→    <div className="flex-1 overflow-y-auto">
 86→      <div className="max-w-[1400px] mx-auto px-4 md:px-6 lg:px-8 py-6 space-y-6">
 87→        {/* Header */}
 88→        <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between sm:gap-4">
 89→          <div>
 90→            <h1 className="text-xl font-bold text-foreground">Kandidaten</h1>
 91→            <p className="text-sm text-muted-foreground mt-1">
 92→              Talent pool — overzicht van alle kandidaten
 93→            </p>
 94→          </div>
 95→          <AddCandidateDialog />
 96→        </div>
 97→
 98→        {/* KPI row */}
 99→        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
100→          <KPICard icon={<Users className="h-4 w-4" />} label="Totaal" value={totalCount} />
101→          <KPICard
102→            icon={<Zap className="h-4 w-4" />}
103→            label="Direct beschikbaar"
104→            value={directCount}
105→            valueClassName="text-primary"
106→          />
107→          <KPICard
108→            icon={<UserPlus className="h-4 w-4" />}
109→            label="Nieuw deze week"
110→            value={weekCount}
111→          />
112→        </div>
113→
114→        {/* Search + filters */}
115→        <form className="flex flex-col sm:flex-row gap-3">
116→          <div className="relative flex-1">
117→            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
118→            <input
119→              type="text"
120→              name="q"
121→              defaultValue={query}
122→              placeholder="Zoek op naam..."
123→              className="w-full h-9 pl-9 pr-3 bg-card border border-border rounded-lg text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:border-primary/40"
124→            />
125→          </div>
126→          <select
127→            name="beschikbaarheid"
128→            defaultValue={availability}
129→            className="h-9 px-3 bg-card border border-border rounded-lg text-sm text-muted-foreground focus:outline-none focus:border-primary/40"
130→          >
131→            <option value="">Alle beschikbaarheid</option>
132→            <option value="direct">Direct beschikbaar</option>
133→            <option value="1_maand">Binnen 1 maand</option>
134→            <option value="3_maanden">Binnen 3 maanden</option>
135→          </select>
136→          <button
137→            type="submit"
138→            className="h-9 px-4 bg-primary hover:bg-primary/90 text-white text-sm font-medium rounded-lg transition-colors"
139→          >
140→            Zoeken
141→          </button>
142→        </form>
143→
144→        {/* Results count */}
145→        <div className="flex items-center justify-between">
146→          <p className="text-sm text-muted-foreground">{totalCount} kandidaten gevonden</p>
147→          {totalPages > 1 && (
148→            <p className="text-sm text-muted-foreground">
149→              Pagina {page} van {totalPages}
150→            </p>
151→          )}
152→        </div>
153→
154→        {/* Grid */}
155→        {candidateRows.length === 0 ? (
156→          <EmptyState
157→            icon={<Users className="h-8 w-8" />}
158→            title="Geen kandidaten gevonden"
159→            subtitle="Pas je zoekopdracht of filters aan"
160→          />
161→        ) : (
162→          <div className="grid gap-3 md:grid-cols-2 xl:grid-cols-3">
163→            {candidateRows.map((candidate) => {
164→              const skills = Array.isArray(candidate.skills) ? (candidate.skills as string[]) : [];
165→
166→              return (
167→                <DraggableCandidate
168→                  key={candidate.id}
169→                  candidateId={candidate.id}
170→                  candidateName={candidate.name}
171→                >
172→                  <Link href={`/professionals/${candidate.id}`}>
173→                    <div className="bg-card border border-border rounded-lg p-4 hover:border-primary/40 hover:bg-accent transition-colors cursor-pointer pl-6">
174→                      {/* Name + source */}
175→                      <div className="flex items-start justify-between gap-2 mb-3">
176→                        <div>
177→                          <h3 className="text-sm font-semibold text-foreground leading-snug">
178→                            {candidate.name}
179→                          </h3>
180→                          {candidate.role && (
181→                            <p className="text-xs text-muted-foreground mt-0.5">{candidate.role}</p>
182→                          )}
183→                        </div>
184→                        {candidate.source && (
185→                          <Badge
186→                            variant="outline"
187→                            className="shrink-0 text-[10px] capitalize border-border text-muted-foreground bg-transparent"
188→                          >
189→                            {candidate.source}
