127→        });
128→
129→        if (uploadRes.ok) {
130→          const { parsed, fileUrl } = await uploadRes.json();
131→
132→          setLoadingMessage("CV koppelen aan kandidaat...");
133→          await fetch("/api/cv-upload/save", {
134→            method: "POST",
135→            headers: { "Content-Type": "application/json" },
136→            body: JSON.stringify({
137→              parsed,
138→              fileUrl,
139→              existingCandidateId: candidate.id,
140→            }),
141→          });
142→        }
143→        // CV upload failure is non-fatal — candidate is already created
144→      }
145→
146→      setOpen(false);
147→      setCvFile(null);
148→      form.reset();
149→      router.refresh();
150→    } catch (err) {
151→      setError(err instanceof Error ? err.message : "Opslaan mislukt.");
152→    } finally {
153→      setLoading(false);
154→      setLoadingMessage("");
155→    }
156→  };
