 1→import { revalidatePath } from "next/cache";
 2→import { z } from "zod";
 3→import { withApiHandler } from "@/src/lib/api-handler";
 4→import { paginatedResponse, parsePagination } from "@/src/lib/pagination";
 5→import {
 6→  countCandidates,
 7→  createCandidate,
 8→  listCandidates,
 9→  searchCandidates,
10→} from "@/src/services/candidates";
11→
12→export const dynamic = "force-dynamic";
13→
14→const createCandidateSchema = z.object({
15→  name: z.string().min(1),
16→  email: z.string().email().optional(),
17→  phone: z.string().optional(),
18→  role: z.string().optional(),
19→  skills: z.array(z.string()).optional(),
20→  location: z.string().optional(),
21→  source: z.string().optional(),
22→  linkedinUrl: z.string().url().optional(),
23→  headline: z.string().optional(),
24→  hourlyRate: z.number().int().positive().optional(),
25→  availability: z.enum(["direct", "1_maand", "3_maanden"]).optional(),
26→  notes: z.string().optional(),
27→  experience: z
28→    .array(z.object({ title: z.string(), company: z.string(), duration: z.string() }))
29→    .optional(),
30→  education: z
31→    .array(z.object({ school: z.string(), degree: z.string(), duration: z.string() }))
32→    .optional(),
33→});
34→
35→export const GET = withApiHandler(async (request: Request) => {
36→  const params = new URL(request.url).searchParams;
37→  const q = params.get("q") ?? undefined;
38→  const location = params.get("locatie") ?? params.get("location") ?? undefined;
39→  const { page, limit, offset } = parsePagination(params);
40→
41→  const useSearch = Boolean(q || location);
42→  const data = useSearch
43→    ? await searchCandidates({ query: q, location, limit, offset })
44→    : await listCandidates({ limit, offset });
45→  const total = useSearch ? await countCandidates({ query: q, location }) : await countCandidates();
46→
47→  return Response.json(paginatedResponse(data, total, { page, limit, offset }));
48→});
49→
50→export const POST = withApiHandler(async (request: Request) => {
51→  const body = await request.json();
52→  const parsed = createCandidateSchema.safeParse(body);
53→  if (!parsed.success) {
54→    return Response.json(
55→      { error: "Ongeldige invoer", details: parsed.error.flatten() },
56→      { status: 400 },
