  1→import { asc, eq, gte, sql } from "drizzle-orm";
  2→import { db } from "../db";
  3→import { scrapeResults, scraperConfigs } from "../db/schema";
  4→import { decrypt, encrypt } from "../lib/crypto";
  5→
  6→// ========== Types ==========
  7→
  8→export type ScraperConfig = typeof scraperConfigs.$inferSelect;
  9→
 10→export type PlatformHealth = {
 11→  platform: string;
 12→  isActive: boolean;
 13→  lastRunAt: Date | null;
 14→  lastRunStatus: string | null;
 15→  consecutiveFailures: number;
 16→  circuitBreakerOpen: boolean;
 17→  runs24h: number;
 18→  failures24h: number;
 19→  failureRate: number;
 20→  status: "gezond" | "waarschuwing" | "kritiek" | "inactief";
 21→};
 22→
 23→export type HealthReport = {
 24→  data: PlatformHealth[];
 25→  overall: "gezond" | "waarschuwing" | "kritiek";
 26→};
 27→
 28→export type UpdateConfigData = {
 29→  isActive?: boolean;
 30→  cronExpression?: string;
 31→  parameters?: Record<string, unknown>;
 32→};
 33→
 34→// ========== Service Functions ==========
 35→
 36→/** Alle scraper configuraties ophalen, gesorteerd op platform */
 37→export async function getAllConfigs(): Promise<ScraperConfig[]> {
 38→  return db.select().from(scraperConfigs).orderBy(asc(scraperConfigs.platform));
 39→}
 40→
 41→/** Eén scraper configuratie bijwerken op ID. Geeft de bijgewerkte rij terug, of null als niet gevonden. */
 42→export async function updateConfig(
 43→  id: string,
 44→  data: UpdateConfigData,
 45→): Promise<ScraperConfig | null> {
 46→  const result = await db
 47→    .update(scraperConfigs)
 48→    .set({
 49→      ...data,
 50→      updatedAt: new Date(),
 51→    })
 52→    .where(eq(scraperConfigs.id, id))
 53→    .returning();
 54→
 55→  return result[0] ?? null;
 56→}
 57→
 58→/** Platform gezondheidsrapport: status per scraper + 24-uurs failure rate */
 59→export async function getHealth(): Promise<HealthReport> {
 60→  const twentyFourHoursAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
 61→
 62→  const configs = await db.select().from(scraperConfigs);
 63→  const statsRows = await db
 64→    .select({
 65→      platform: scrapeResults.platform,
 66→      total: sql<number>`count(*)::int`,
 67→      failures: sql<number>`count(*) filter (where ${scrapeResults.status} = 'failed')::int`,
 68→    })
 69→    .from(scrapeResults)
 70→    .where(gte(scrapeResults.runAt, twentyFourHoursAgo))
 71→    .groupBy(scrapeResults.platform);
 72→
 73→  const statsMap = new Map(statsRows.map((s) => [s.platform, s]));
 74→
 75→  const health: PlatformHealth[] = configs.map((cfg) => {
 76→    const failures = cfg.consecutiveFailures ?? 0;
 77→
 78→    if (!cfg.isActive) {
 79→      return {
 80→        platform: cfg.platform,
 81→        isActive: false,
 82→        lastRunAt: cfg.lastRunAt,
 83→        lastRunStatus: cfg.lastRunStatus,
 84→        consecutiveFailures: failures,
 85→        circuitBreakerOpen: failures >= 5,
 86→        runs24h: 0,
 87→        failures24h: 0,
 88→        failureRate: 0,
 89→        status: "inactief" as const,
 90→      };
 91→    }
 92→
 93→    const stats = statsMap.get(cfg.platform);
 94→    const runs24h = stats?.total ?? 0;
 95→    const failures24h = stats?.failures ?? 0;
 96→    const failureRate = runs24h > 0 ? failures24h / runs24h : 0;
 97→
 98→    let status: PlatformHealth["status"] = "gezond";
 99→    if (failures24h > 3) {
100→      status = "kritiek";
101→    } else if (failures24h > 0) {
102→      status = "waarschuwing";
103→    }
104→
105→    // Promote to kritiek if circuit breaker is open
106→    if (failures >= 5) {
107→      status = "kritiek";
108→    }
109→
110→    return {
111→      platform: cfg.platform,
112→      isActive: cfg.isActive,
113→      lastRunAt: cfg.lastRunAt,
114→      lastRunStatus: cfg.lastRunStatus,
115→      consecutiveFailures: failures,
116→      circuitBreakerOpen: failures >= 5,
117→      runs24h,
118→      failures24h,
119→      failureRate: Math.round(failureRate * 100) / 100,
120→      status,
121→    };
122→  });
123→
124→  const overall: HealthReport["overall"] = health.some((h) => h.status === "kritiek")
125→    ? "kritiek"
126→    : health.some((h) => h.status === "waarschuwing")
127→      ? "waarschuwing"
128→      : "gezond";
129→
130→  return { data: health, overall };
131→}
