 1→import type { NextRequest } from "next/server";
 2→import { z } from "zod";
 3→import { withApiHandler } from "@/src/lib/api-handler";
 4→import { updateConfig } from "@/src/services/scrapers";
 5→
 6→export const dynamic = "force-dynamic";
 7→
 8→const patchSchema = z
 9→  .object({
10→    isActive: z.boolean().optional(),
11→    cronExpression: z.string().max(100).optional(),
12→    parameters: z.record(z.unknown()).optional(),
13→  })
14→  .refine((data) => Object.values(data).some((v) => v !== undefined), {
15→    message: "Minimaal één veld vereist",
16→  });
17→
18→export const PATCH = withApiHandler(
19→  async (request: NextRequest, { params }: { params: Promise<{ id: string }> }) => {
20→    const { id } = await params;
21→    const body = await request.json();
22→
23→    const parsed = patchSchema.safeParse(body);
24→    if (!parsed.success) {
25→      return Response.json(
26→        { error: "Ongeldige invoer", details: parsed.error.flatten() },
27→        { status: 400 },
28→      );
29→    }
30→
31→    const config = await updateConfig(id, parsed.data);
32→    if (!config) {
33→      return Response.json({ error: "Scraper configuratie niet gevonden" }, { status: 404 });
34→    }
35→
36→    return Response.json({ data: config });
37→  },
38→  {
39→    logPrefix: "Fout bij bijwerken scraper configuratie",
40→    errorMessage: "Kan scraper configuratie niet bijwerken",
41→  },
42→);
